<?php
declare(strict_types=1);
require_once __DIR__ . '/../includes/ecosystem.php';
$beyondWallet = beyond_app_bootstrap('DailyBreath');
$pdo = beyond_db();

require_once __DIR__ . '/includes/verse-of-day.php';
$dailyVerse = dailybreath_verse_of_day($pdo, (string)($_SESSION['locale'] ?? 'en'));
$dailyTitle = $dailyVerse['text'];
$dailyBody = $dailyVerse['reference'];
$dailyBibleUrl = dailybreath_bible_url($dailyVerse);

$devotional = ['title'=>'Walk in Quiet Confidence','excerpt'=>'Make room for stillness and remember that God is present before your next step.','scripture_reference'=>'Psalm 46:10','duration_minutes'=>5];
try {
    $query = $pdo->prepare('SELECT title,excerpt,scripture_reference,duration_minutes FROM devotionals WHERE is_published=1 AND locale=? AND publish_date<=? ORDER BY publish_date DESC,id DESC LIMIT 1');
    $query->execute([$_SESSION['locale'] ?? 'en', date('Y-m-d')]);
    $devotional = $query->fetch(PDO::FETCH_ASSOC) ?: $devotional;
} catch (Throwable $exception) {}

$name = trim((string)($_SESSION['name'] ?? '')) ?: 'Friend';
?>
